// ============================================================================
// VALIDATE INPUT
// Extract contract_id and position scale context from request body
// ============================================================================

let body = $input.first().json.body || $input.first().json || {};

if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) { throw new Error('Invalid JSON in request body'); }
}

const contractId = body.contract_id || body.contractId;
if (!contractId) throw new Error('contract_id is required');

// Extract position scale context fields (may be null for older triggers)
const contractTypeKey = body.contract_type_key || body.contractTypeKey || null;
const initiatorPartyRole = body.initiator_party_role || body.initiatorPartyRole || null;

console.log('=== CERTIFY NEXT CLAUSE ===' );
console.log('Contract ID:', contractId);
console.log('Contract Type Key:', contractTypeKey);
console.log('Initiator Party Role:', initiatorPartyRole);

// Pass through roleContext if provided by the API (canonical Role Matrix labels)
const roleContext = body.roleContext || null;

return { json: { contractId, contractTypeKey, initiatorPartyRole, roleContext } };

// ============================================================================
// CHECK IF WE HAVE A PENDING CLAUSE
// If Postgres returned no rows, clause_id will be undefined
// ============================================================================

const result = $input.first().json;
const hasPending = !!(result && result.clause_id);

console.log('Has pending clause:', hasPending);
if (hasPending) {
  console.log('Next clause:', result.clause_number, '-', result.clause_name);
  console.log('Progress:', result.certified_count, '/', result.total_certifiable, 'certified');
}

return {
  json: {
    ...result,
    contractId: $('Validate Input').first().json.contractId,
    hasPending
  }
};

