// ============================================================================
// PREPARE CERTIFICATION REQUEST
// Locate the clause in the document, resolve party labels, build Claude prompt
// ============================================================================

const contractId = $("Validate Input").first().json.contractId;
const clauseData = $("Check Result").first().json;
const docData = $input.first().json;

const documentText = docData.extracted_text || "";
const allClauses = docData.all_clauses || [];
const contractType = docData.detected_contract_type || "contract";

// ---- Resolve contract type and party labels ----
// Prefer webhook value, fall back to DB value from uploaded_contracts
const contractTypeKey = $("Validate Input").first().json.contractTypeKey || docData.contract_type_key || null;
const initiatorPartyRole = $("Validate Input").first().json.initiatorPartyRole || docData.initiator_party_role || null;

const PARTY_LABELS = {
  'service_agreement':      { protected: 'Customer',         providing: 'Provider' },
  'saas_agreement':         { protected: 'Subscriber',       providing: 'Provider' },
  'it_outsourcing':         { protected: 'Customer',         providing: 'Provider' },
  'bpo_agreement':          { protected: 'Customer',         providing: 'Provider' },
  'managed_services':       { protected: 'Customer',         providing: 'Provider' },
  'consultancy_agreement':  { protected: 'Client',           providing: 'Consultant' },
  'software_license':       { protected: 'Licensee',         providing: 'Licensor' },
  'maintenance_agreement':  { protected: 'Customer',         providing: 'Service Provider' },
  'nda_one_way':            { protected: 'Disclosing Party', providing: 'Receiving Party' },
  'nda_mutual':             { protected: 'Disclosing Parties', providing: 'Receiving Parties' },
  'lease_agreement':        { protected: 'Tenant',           providing: 'Landlord' },
  'loan_agreement':         { protected: 'Borrower',         providing: 'Lender' },
  'insurance_policy':       { protected: 'Policyholder',     providing: 'Insurer' },
  'sales_agreement':        { protected: 'Buyer',            providing: 'Seller' },
  'purchase_agreement':     { protected: 'Buyer',            providing: 'Seller' },
  'distribution_agreement': { protected: 'Distributor',      providing: 'Supplier' },
  'franchise_agreement':    { protected: 'Franchisee',       providing: 'Franchisor' },
  'employment_contract':    { protected: 'Employee',         providing: 'Employer' },
  'construction_contract':  { protected: 'Client',           providing: 'Contractor' },
  'agency_agreement':       { protected: 'Principal',        providing: 'Agent' },
};

// Prefer passed roleContext from the API (canonical Role Matrix source), fall back to local map
const passedRoleContext = $("Validate Input").first().json.roleContext || null;
const labels = passedRoleContext ? { protected: passedRoleContext.protectedPartyLabel, providing: passedRoleContext.providingPartyLabel } : (PARTY_LABELS[contractTypeKey] || { protected: 'Protected Party', providing: 'Providing Party' });
const protectedLabel = labels.protected;
const providingLabel = labels.providing;
const isMutual = contractTypeKey && contractTypeKey.includes('mutual');

console.log("=== PREPARE CERTIFICATION ===");
console.log("Clause:", clauseData.clause_number, "-", clauseData.clause_name);
console.log("Document length:", documentText.length);
console.log("Contract Type Key:", contractTypeKey);
console.log("Party Labels:", protectedLabel, "/", providingLabel);
console.log("Is Mutual:", isMutual);

const mutualContext = isMutual ? `\nMUTUAL AGREEMENT NOTE:\n- Both parties are SIMULTANEOUSLY ${protectedLabel} AND ${providingLabel} in this agreement.\n- The scale measures DEGREE OF RESTRICTION on information, not which party benefits (both are equally affected).\n- Low positions (1-4): More PERMISSIVE — greater flexibility in how received information can be used.\n- High positions (7-10): More RESTRICTIVE — stronger obligations to protect disclosed information.\n- In your assessment, describe whether the clause is more restrictive or more permissive, not which party it favours.\n- Example position 3: "This clause is relatively permissive, allowing greater flexibility for ${providingLabel} in how information is handled."\n- Example position 7: "This clause is moderately restrictive, imposing stronger obligations to protect information disclosed by ${protectedLabel}."\n` : '';

// ---- Find clause location in document ----
function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function findClauseSection(docText, clauseNum, snippet, clauses) {
  let startIdx = -1;

  // Strategy 1: Find by snippet text
  if (snippet && snippet.length > 20) {
    const clean = snippet.replace(/\.{3,}$/, "").trim();
    if (clean.length > 15) {
      const searchStr = clean.substring(0, Math.min(clean.length, 60));
      startIdx = docText.indexOf(searchStr);
    }
  }

  // Strategy 2: Find by clause number pattern
  if (startIdx === -1) {
    const escaped = escapeRegex(clauseNum);
    const patterns = [
      new RegExp("\\n\\s*" + escaped + "[.\\s\\t]"),
      new RegExp("\\b" + escaped + "\\b"),
    ];
    for (const p of patterns) {
      const m = p.exec(docText);
      if (m) {
        startIdx = m.index;
        break;
      }
    }
  }

  // Strategy 3: Find by clause name
  if (startIdx === -1 && clauseData.clause_name) {
    startIdx = docText.toLowerCase().indexOf(clauseData.clause_name.toLowerCase());
  }

  if (startIdx === -1) {
    console.log("WARNING: Could not locate clause in document, using first 10000 chars");
    return docText.substring(0, Math.min(docText.length, 10000));
  }

  // Find end boundary: look for the next clause
  const currentOrder = (clauses || []).find((c) => c.clause_number === clauseNum)?.display_order || 0;
  const nextClauses = (clauses || [])
    .filter((c) => c.display_order > currentOrder)
    .sort((a, b) => a.display_order - b.display_order);

  let endIdx = startIdx + 20000;

  for (const next of nextClauses.slice(0, 5)) {
    const nextEscaped = escapeRegex(next.clause_number);
    try {
      const nextPattern = new RegExp("\\n\\s*" + nextEscaped + "[.\\s\\t]");
      const searchFrom = docText.substring(startIdx + 20);
      const nextMatch = nextPattern.exec(searchFrom);
      if (nextMatch) {
        endIdx = startIdx + 20 + nextMatch.index + 200;
        break;
      }
    } catch (e) { /* skip invalid regex */ }
  }

  const contextStart = Math.max(0, startIdx - 300);
  endIdx = Math.min(docText.length, endIdx);

  return docText.substring(contextStart, endIdx);
}

const relevantSection = findClauseSection(
  documentText,
  clauseData.clause_number,
  clauseData.snippet,
  allClauses,
);

console.log("Extracted section length:", relevantSection.length, "chars");

// ---- Build Claude prompt with position scale context ----
const prompt = `You are CLARENCE — a legal contract certification engine. Your task is to certify ONE specific clause OBJECTIVELY.

CONTRACT TYPE: ${contractType}${contractTypeKey ? ' (' + contractTypeKey + ')' : ''}

POSITION SCALE (YOU MUST FOLLOW THIS):
- Position 1: Maximum flexibility for ${providingLabel}
- Position 2: Strong ${providingLabel} terms
- Position 3: ${providingLabel}-leaning but reasonable
- Position 4: Slight ${providingLabel} advantage
- Position 5: Balanced / Market standard
- Position 6: Slight ${protectedLabel} advantage
- Position 7: Moderate protection for ${protectedLabel}
- Position 8: Strong protection for ${protectedLabel}
- Position 9: Very high protection for ${protectedLabel}
- Position 10: Maximum protection for ${protectedLabel}

CRITICAL RULES:
- The position number you assign and the assessment text MUST be consistent.
- If you assign position 7, the assessment MUST say it favours/protects ${protectedLabel}.
- If you assign position 3, the assessment MUST say it favours ${providingLabel}.
- If you assign position 5, the assessment MUST say it is balanced or market standard.
- NEVER say a low position (1-4) favours ${protectedLabel}.
- NEVER say a high position (7-10) favours ${providingLabel}.
- Use the party labels above (${protectedLabel}/${providingLabel}), NOT generic terms.
${mutualContext}
CLAUSE TO CERTIFY:
Number: ${clauseData.clause_number}
Name: ${clauseData.clause_name}
Category: ${clauseData.category}

DOCUMENT TEXT (section containing this clause):
---
${relevantSection}
---

YOUR TASKS:

1. EXTRACT FULL TEXT: Find clause ${clauseData.clause_number} in the text above. Extract its COMPLETE text - every word until the next clause begins. Do not truncate.

2. POSITION (1.0-10.0 scale): Using the scale above. 1.0 = Maximum flexibility for ${providingLabel}. 10.0 = Maximum protection for ${protectedLabel}.

3. FAIRNESS: One of: "balanced", "slightly_customer_favoring", "customer_favoring", "heavily_customer_favoring", "slightly_provider_favoring", "provider_favoring", "heavily_provider_favoring", "review_recommended"\n   - Use "customer" side when the clause favours ${protectedLabel} (the protected party)\n   - Use "provider" side when the clause favours ${providingLabel} (the providing party)\n   - "slightly" = positions 4 or 6, "customer/provider_favoring" = positions 3 or 7-8, "heavily" = positions 1-2 or 9-10

4. SUMMARY: One sentence describing what this clause does.

5. ASSESSMENT: 2-3 sentences explaining your position rating. Use the party labels ${protectedLabel} and ${providingLabel}. The assessment MUST be consistent with the position number per the scale above.
   - IMPORTANT: Many clauses have MULTIPLE dimensions (e.g., a mediation clause may cover both whether mediation is mandatory AND the notice period). Your assessment must address ALL key dimensions, not just the most easily quantifiable one.
   - Base the position on the OVERALL effect of the clause considering all its elements together.
   - Mention specific terms from the clause (e.g., "mandatory mediation with 30-day notice" not just "30 days").

6. FLAGS: Any concerns, unusual provisions, or missing protections. Empty array if none.

7. VALUE EXTRACTION: If the clause contains a specific quantifiable value (duration, amount, percentage), extract it. Otherwise null.

Return ONLY valid JSON - no markdown, no backticks, no explanation:
{
  "full_text": "The complete clause text...",
  "position": 6.5,
  "fairness": "slightly_customer_favoring",
  "summary": "This clause establishes...",
  "assessment": "This clause provides moderate protection for ${protectedLabel} by...",
  "flags": ["Extended payment period"],
  "extracted_value": "45",
  "extracted_unit": "days",
  "value_type": "duration"
}`;

const requestBody = {
  model: "claude-sonnet-4-20250514",
  max_tokens: 8192,
  temperature: 0,
  messages: [{ role: "user", content: prompt }],
};

return {
  json: {
    contractId,
    clauseId: clauseData.clause_id,
    clauseNumber: clauseData.clause_number,
    clauseName: clauseData.clause_name,
    claudeRequestBody: requestBody,
  },
};

// ============================================================================
// PROCESS CLAUDE CERTIFICATION RESPONSE
// Parse the JSON response and prepare for database update
// ============================================================================

const input = $('Prepare Certification Request').first().json;
const response = $input.first().json;

console.log('=== PROCESS CERTIFICATION RESPONSE ===' );
console.log('Clause:', input.clauseNumber, '-', input.clauseName);

const content = response.content || [];
const textBlock = content.find(b => b.type === 'text');
const responseText = textBlock?.text || '';

// Parse JSON from response
let parsed;
try {
  let jsonStr = responseText.trim();
  // Strip markdown code fences if present
  if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
  }
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // Try to find JSON object in the response
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch(e2) {
      console.error('Failed to parse response:', responseText.substring(0, 300));
      throw new Error('Failed to parse certification response as JSON');
    }
  } else {
    console.error('No JSON found in response:', responseText.substring(0, 300));
    throw new Error('No JSON found in Claude certification response');
  }
}

console.log('Position:', parsed.position);
console.log('Fairness (raw):', parsed.fairness);
console.log('Full text length:', (parsed.full_text || '').length);

// Validate fairness against DB constraint
const VALID_FAIRNESS = ['balanced', 'slightly_customer_favoring', 'customer_favoring', 'heavily_customer_favoring', 'slightly_provider_favoring', 'provider_favoring', 'heavily_provider_favoring', 'review_recommended'];
let fairness = parsed.fairness || 'balanced';
if (!VALID_FAIRNESS.includes(fairness)) {
  console.warn('Invalid fairness value:', fairness, '- mapping from position');
  const pos = parseFloat(parsed.position) || 5.0;
  if (pos >= 4.5 && pos <= 5.5) fairness = 'balanced';
  else if (pos > 5.5 && pos <= 6.5) fairness = 'slightly_customer_favoring';
  else if (pos > 6.5 && pos <= 8.0) fairness = 'customer_favoring';
  else if (pos > 8.0) fairness = 'heavily_customer_favoring';
  else if (pos >= 3.5 && pos < 4.5) fairness = 'slightly_provider_favoring';
  else if (pos >= 2.0 && pos < 3.5) fairness = 'provider_favoring';
  else fairness = 'heavily_provider_favoring';
  console.log('Mapped fairness to:', fairness);
}
console.log('Fairness (final):', fairness);

// Sanitize text for SQL
function sanitize(text) {
  if (!text) return '';
  return text.replace(/\u0000/g, '').trim();
}

return {
  json: {
    contractId: input.contractId,
    clauseId: input.clauseId,
    clauseNumber: input.clauseNumber,
    fullText: sanitize(parsed.full_text || ''),
    position: parseFloat(parsed.position) || 5.0,
    fairness: fairness,
    summary: sanitize(parsed.summary || ''),
    assessment: sanitize(parsed.assessment || ''),
    flags: JSON.stringify(parsed.flags || []),
    extractedValue: parsed.extracted_value || null,
    extractedUnit: parsed.extracted_unit || null,
    valueType: parsed.value_type || null
  }
};

