// ============================================================================
// BUILD SINGLE CLAUSE RANGE MAPPING PAYLOAD
// Uses data already in the pipeline from Process Certification Response
// Fires per-clause so real-world values are ready when the user clicks
// ============================================================================

const contractId = $("Validate Input").first().json.contractId;
const certData = $("Process Certification Response").first().json;
const docData = $("Get Document Text").first().json;

const clause = {
  clause_id: certData.clauseId,
  clause_number: certData.clauseNumber,
  clause_name:
    certData.clauseName || $("Check Result").first().json.clause_name,
  category: $("Check Result").first().json.category || "Other",
  content: certData.fullText || $("Check Result").first().json.snippet || "",
  extracted_value: certData.extractedValue || null,
  extracted_unit: certData.extractedUnit || null,
  value_type: certData.valueType || null,
  document_position: null,
  clarence_position: certData.position || null,
};

const contractType = docData.detected_contract_type || "service_agreement";

console.log(
  `=== RANGE MAPPING: ${clause.clause_number} - ${clause.clause_name} ===`,
);
console.log(
  `Position: ${clause.clarence_position}, Value: ${clause.extracted_value} ${clause.extracted_unit || ""}`,
);

return {
  json: {
    payload: {
      contract_id: contractId,
      clauses: [clause],
      contract_type: contractType,
      force_refresh: false,
    },
  },
};
